import{_ as s,o as a,c as n,ag as e}from"./chunks/framework.BbyMWZAR.js";const h=JSON.parse('{"title":"HTTP vs HTTPS：TLS 握手过程与加密原理","description":"","frontmatter":{"title":"HTTP vs HTTPS：TLS 握手过程与加密原理","difficulty":"hard","tags":["HTTPS","TLS","SSL","加密"],"estimate":30},"headers":[],"relativePath":"domains/browser/qa/qa-10-https-tls.md","filePath":"domains/browser/qa/qa-10-https-tls.md","lastUpdated":1783504823000}'),i={name:"domains/browser/qa/qa-10-https-tls.md"};function r(t,l,o,p,T,S){return a(),n("div",null,[...l[0]||(l[0]=[e(`<h1 id="问答-10-高级-http-vs-https-tls-握手过程与加密原理" tabindex="-1">问答 10（高级）：HTTP vs HTTPS：TLS 握手过程与加密原理 <a class="header-anchor" href="#问答-10-高级-http-vs-https-tls-握手过程与加密原理" aria-label="Permalink to &quot;问答 10（高级）：HTTP vs HTTPS：TLS 握手过程与加密原理&quot;">​</a></h1><h2 id="题目" tabindex="-1">题目 <a class="header-anchor" href="#题目" aria-label="Permalink to &quot;题目&quot;">​</a></h2><p>HTTP 和 HTTPS 有什么区别？HTTPS 的握手过程是怎样的？TLS 1.2 与 TLS 1.3 有什么区别？请说明 HTTPS 是怎么同时实现「机密性 / 完整性 / 身份认证」的。</p><h2 id="参考答案" tabindex="-1">参考答案 <a class="header-anchor" href="#参考答案" aria-label="Permalink to &quot;参考答案&quot;">​</a></h2><p><strong>HTTP vs HTTPS</strong></p><ul><li>HTTP：明文，任何中间节点都能看和改。</li><li>HTTPS = HTTP + TLS（Transport Layer Security，SSL 的后继者）。</li><li>HTTPS 三个保证： <ul><li><strong>机密性</strong>：对称加密（AES-GCM / ChaCha20）保证第三方看不到内容。</li><li><strong>完整性</strong>：MAC / AEAD 保证内容没被篡改。</li><li><strong>身份认证</strong>：证书 + PKI 体系保证服务器确实是那个域名的持有者。</li></ul></li></ul><p><strong>TLS 1.2 握手（经典，2-RTT）</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Client                                            Server</span></span>
<span class="line"><span>  |----- ClientHello（版本、随机数、密码套件列表）-----------&gt;|</span></span>
<span class="line"><span>  |&lt;---- ServerHello（选定套件、随机数）---------------------|</span></span>
<span class="line"><span>  |&lt;---- Certificate（服务器证书链）------------------------|</span></span>
<span class="line"><span>  |&lt;---- ServerKeyExchange（如 ECDHE 参数）-----------------|</span></span>
<span class="line"><span>  |&lt;---- ServerHelloDone ---------------------------------|</span></span>
<span class="line"><span>  |----- ClientKeyExchange（客户端 ECDHE 公钥）-----------&gt;|</span></span>
<span class="line"><span>  |----- ChangeCipherSpec + Finished ---------------------&gt;|</span></span>
<span class="line"><span>  |&lt;---- ChangeCipherSpec + Finished --------------------|</span></span>
<span class="line"><span>  |=== 应用数据（对称加密）=============================&gt;|</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><ul><li>交换随机数 + 通过 ECDHE 密钥交换生成「预主密钥」，双方各自派生出会话密钥。</li><li>证书链用于验证服务器身份（浏览器根据内置 Root CA 校验）。</li><li>需要 2 个 RTT 才能开始发应用数据。</li></ul><p><strong>TLS 1.3 握手（1-RTT，甚至 0-RTT）</strong></p><ul><li>移除不安全算法（RSA 密钥交换、静态 DH、CBC 模式等），只保留 AEAD（AES-GCM、ChaCha20-Poly1305）。</li><li>密码套件与密钥交换分离，握手更简洁。</li><li>客户端在 ClientHello 里就带上 ECDHE 公钥参数（key_share），服务器 ServerHello 返回自己的 key_share，第一次交互双方就能算出会话密钥。</li><li>立即用会话密钥加密后续握手报文（证书、Finished）。</li><li><strong>0-RTT</strong>（会话恢复）：客户端复用之前的 PSK，第一封数据包就带上应用数据；有重放风险，通常只允许幂等 GET。</li></ul><p><strong>加密的分工</strong></p><ul><li><strong>非对称加密</strong>（ECDHE / RSA）：只用来<strong>协商对称密钥</strong>，慢但只做一次。</li><li><strong>对称加密</strong>（AES-GCM）：<strong>加密应用数据</strong>，快。</li><li><strong>数字签名</strong>：服务器用私钥对握手过程签名，客户端用证书里的公钥验证，防中间人冒充。</li><li><strong>哈希 / MAC / AEAD</strong>：保证消息完整性。</li></ul><p><strong>证书链与信任</strong></p><ul><li>服务器提供证书（含域名、公钥、签发者、有效期）。</li><li>证书由中间 CA 签发，中间 CA 由 Root CA 签发。</li><li>浏览器 / OS 内置 Root CA 列表，用它验证整条链。</li><li>校验点：域名匹配（SAN）、有效期、吊销状态（OCSP / CRL）、密钥算法安全性。</li></ul><h2 id="追问-1-为什么不直接用非对称加密传所有数据-还要那么麻烦切换到对称" tabindex="-1">追问 1：为什么不直接用非对称加密传所有数据？还要那么麻烦切换到对称？ <a class="header-anchor" href="#追问-1-为什么不直接用非对称加密传所有数据-还要那么麻烦切换到对称" aria-label="Permalink to &quot;追问 1：为什么不直接用非对称加密传所有数据？还要那么麻烦切换到对称？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li><strong>性能</strong>：非对称（RSA / ECC）比对称（AES）慢几百到上千倍。传大量数据时太贵。</li><li><strong>数据长度限制</strong>：RSA 加密的明文长度受 key 长度限制（如 2048 位 RSA 一次最多加密 245 字节）。</li><li><strong>前向保密</strong>：如果一直用同一对非对称密钥加密所有会话，一旦服务器私钥泄漏，历史所有报文都能解密。ECDHE 每次会话生成临时密钥，即使私钥泄漏也不能倒推之前的会话（Forward Secrecy）。</li><li>所以架构是：非对称做「握手 + 身份验证 + 密钥协商」，对称做「数据加密」，各取所长。</li></ul><h2 id="追问-2-什么是「中间人攻击-mitm-」-https-是怎么防的-企业-抓包工具为什么还能抓到-https" tabindex="-1">追问 2：什么是「中间人攻击（MITM）」？HTTPS 是怎么防的？企业 / 抓包工具为什么还能抓到 HTTPS？ <a class="header-anchor" href="#追问-2-什么是「中间人攻击-mitm-」-https-是怎么防的-企业-抓包工具为什么还能抓到-https" aria-label="Permalink to &quot;追问 2：什么是「中间人攻击（MITM）」？HTTPS 是怎么防的？企业 / 抓包工具为什么还能抓到 HTTPS？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li>MITM：攻击者插在客户端和服务器之间，转发流量的同时能看和改内容。做法通常是伪造 DNS / ARP，让流量经过自己。</li><li>HTTPS 防范： <ul><li>服务器证书要由可信 CA 签发，MITM 无法伪造有效证书。</li><li>若 MITM 用自签名证书，客户端会看到「不信任」的警告。</li><li>HSTS（<code>Strict-Transport-Security</code>）强制走 HTTPS，防止「SSL 剥离」（把 HTTPS 降级成 HTTP）。</li><li>Certificate Transparency：CA 签发证书要写入公开日志，可审计。</li><li>Certificate Pinning（HPKP 已废弃，改用 Expect-CT / Cert-Pin in app）。</li></ul></li><li>抓包工具（Charles / mitmproxy / Fiddler）能抓 HTTPS 的原理： <ul><li>让用户手动把工具的 Root CA 装入系统 / 浏览器信任库。</li><li>工具动态签发目标域名的证书，用自签 CA 签发；浏览器认为「合法」。</li><li>若没有把 CA 装信任，就会看到证书错误。</li><li>移动端 App 还可以做 SSL Pinning（内置公钥指纹），彻底阻断抓包。</li></ul></li></ul><h2 id="追问-3-为什么-tls-1-3-更安全也更快-0-rtt-有什么风险" tabindex="-1">追问 3：为什么 TLS 1.3 更安全也更快？0-RTT 有什么风险？ <a class="header-anchor" href="#追问-3-为什么-tls-1-3-更安全也更快-0-rtt-有什么风险" aria-label="Permalink to &quot;追问 3：为什么 TLS 1.3 更安全也更快？0-RTT 有什么风险？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li><strong>更安全</strong>： <ul><li>只保留经过审计的密码套件（AEAD、ECDHE）。</li><li>去掉 RSA 密钥交换（无前向保密）、CBC（BEAST / Padding Oracle）、RC4、MD5、SHA-1、压缩（CRIME）等。</li><li>握手报文（除 ClientHello / ServerHello 外）都被加密，观察者看不到证书 / SNI（配合 ECH 可加密 SNI）。</li></ul></li><li><strong>更快</strong>： <ul><li>握手 1-RTT，会话恢复 0-RTT。</li><li>支持 PSK（Pre-Shared Key）机制做会话恢复。</li></ul></li><li><strong>0-RTT 风险</strong>：客户端把请求跟第一封数据包一起发（用之前会话的 PSK 加密）。攻击者可以<strong>重放</strong>这段数据，导致同一请求被服务端处理多次。缓解方式： <ul><li>只对幂等请求（GET / HEAD）开 0-RTT。</li><li>服务端做重放检测（防重放窗口）。</li><li>敏感操作要求 1-RTT 握手完成后再执行。</li></ul></li></ul><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><blockquote><p>深入阅读请从标注 <strong>首选</strong> 的来源开始；本领域完整索引见 <a href="/engineer/handbook/domains/browser/RESOURCES">浏览器 &amp; 网络 参考资料</a>。</p></blockquote><ul><li><strong>首选</strong> — <a href="https://www.rfc-editor.org/rfc/rfc8446" target="_blank" rel="noreferrer">RFC 8446: TLS 1.3</a>：TLS 1.3 握手与 0-RTT 规范</li><li><a href="https://hpbn.co/tls-ssl-performance/" target="_blank" rel="noreferrer">hpbn.co: TLS</a>：TLS 握手过程与性能优化</li><li><a href="https://developer.mozilla.org/en-US/docs/Web/Security/Transport_Layer_Security" target="_blank" rel="noreferrer">MDN: Transport Layer Security</a>：HTTPS 加密原理概览</li></ul>`,27)])])}const g=s(i,[["render",r]]);export{h as __pageData,g as default};
